#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        long long last1 = -1LL<<60, last2 = -1LL<<60;
        long long ans = 0;
        for(int i=0;i<N;i++){
            long long x; scanf("%lld",&x);
            if(x!=last1 && x!=last2){
                ans++;
                last2 = last1;
                last1 = x;
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

